scwin.p_bkno = "";
scwin.p_blno = "";
scwin.p_clntNo = "";
scwin.p_kcomcd = "";
scwin.v_linkcheck = "0";
scwin.p_lobranCd = "";
scwin.p_lobranNm = "";
scwin.p_mhno = "";
scwin.p_seaExgbEx = "";
scwin.strCurDate = "";
scwin.userId = "";
scwin.v_linkcheck = "";
scwin.v_kcomcd = "DBEX";
scwin.v_blno = "";
scwin.v_mhno = "";
scwin.v_bkno = "";
scwin.vCurDate = "";
scwin.vQryBaseMth = "";
scwin.vQryEndDt = "";
scwin.vQryStDt = "";
scwin.ed_mharea = "";
scwin.hd_autono = "DIRECT";
scwin.hd_commcustomer = "999999";
scwin.hd_hhbkgno = "";
scwin.hd_hhblno = "";
scwin.hd_hhbltype = "B";
scwin.hd_hhio = "O";
scwin.hd_kcomcd = "DBEX";
scwin.txt_mhareanm = "";
scwin.tabNo = 0;
scwin.invoiceCheck = "";

//--------------------------------------------------------------------------
//							메세지 상수 선언									//
//--------------------------------------------------------------------------
scwin.MSG_LO_WRN_008 = "이미 전표가 발행  되어 변경 불가능 합니다.";
scwin.MSG_LO_WRN_009 = "Department 가 변경 되었습니다.";

scwin.onpageload = function () {

};

scwin.onUdcCompleted = function () {
    scwin.p_lobranCd = $c.data.getMemInfo("lobranCd") || " ";
    scwin.p_lobranNm = $c.data.getMemInfo("lobranNm") || "";
    scwin.v_linkcheck = $c.data.getParameter("linkcheck") || "";
    scwin.p_kcomcd = $c.data.getParameter("kcomcd") || "";
    scwin.p_mhno = $c.data.getParameter("mhno") || "";
    scwin.p_blno = $c.data.getParameter("blno") || "";
    scwin.p_bkno = $c.data.getParameter("bkno") || "";
    scwin.p_clntNo = $c.data.getParameter("clntNo") || "";
    scwin.p_seaExgbEx = $c.data.getParameter("seaExgbEx") || "";
    scwin.v_kcomcd = scwin.p_kcomcd || "DBEX";
    scwin.v_blno = scwin.p_blno;
    scwin.v_mhno = scwin.p_mhno;
    scwin.v_bkno = scwin.p_bkno;
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.vCurDate = scwin.strCurDate;
    scwin.vQryBaseMth = scwin.vCurDate.substring(0, 6);
    scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";
    scwin.vQryEndDt = scwin.vQryBaseMth + $c.date.getLastDateOfMonth(scwin.vQryBaseMth);

    scwin.f_OnLoad();
}

//---------------------------------------------------------
// 화면로딩시
//---------------------------------------------------------
scwin.f_OnLoad = function () {
    //$p.setTimeout(function() {
    scwin.f_DefaultValue();
    scwin.f_CurrencyLoading(); //환율 코드 정보.
    scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리
    udc_ed_mhetdFrom.setInitDate(scwin.vQryStDt, scwin.vQryEndDt);
    //	$p.clearTimeout("setInit", force);
    //}, { "key":"setInit", "delay":100});
};


//---------------------------------------------------------
// Parameter Setting
// 다른 화면에서 들어올때 각 화면별 조건을 받아서 조회한다.
//---------------------------------------------------------
scwin.f_getParametrSetting = function (gubun) {
    gubun = Number(gubun);
    switch (gubun) {
        case 0:
            break;

        case 1: //Booking의 search Grid
            if (scwin.v_mhno == "null") {
                cnd_ed_mhno.setValue("");
                cnd_ed_mhno.focus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_mhno.setValue(scwin.v_mhno);
            scwin.f_Retrieve();
            break;

        case 2: //House Search에서 던짐.
            if (scwin.v_mhno == "null") {
                cnd_ed_mhno.setValue("");
                cnd_ed_mhno.focus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_mhno.setValue(scwin.v_mhno);
            scwin.f_Retrieve();
            break;

        case 4: // Booking 에서 h b/l버튼 (create)
            scwin.f_Create();
            scwin.hd_hhbkgno = "";
            scwin.f_BookingLoading();
            tab_main.setSelectedTabIndex(0); // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_mhlinercd.focus();
            break;
    }
};

//---------------------------------------------------------
// Object Check
//---------------------------------------------------------
scwin.f_Check = function () {

};

//-------------------------------------------------------------------------
// 초기화
// DATASET이 많으므로 신경써서 봐야합니다.
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    scwin.f_Set("INIT");
    lc_hhincoterm.setSelectedIndex(-1);
    lc_hhexgb.setSelectedIndex(-1);
    lc_mexgb.setSelectedIndex(-1);
    //       	cnd_ed_mhno.focus();
};

//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
    tab_main.setSelectedTabIndex(0);
};

//---------------------------------------------------------
// Tab Menu 선택시 처리
//---------------------------------------------------------
scwin.f_selectTabMenu = function (idx) {
    switch (idx) {
        case 0: //Main tab
            scwin.tabNo = 0;
            break;

        case 1: //Other tab
            scwin.tabNo = 1;
            break;
    }

    tab_main.setSelectedTabIndex(idx);
};

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": //초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Save, btn_Delete, btn_Update
                , btn_2, btn_3, btn_10, btn_5, btn_6, btn_7
                , grpBtn1, grpBtn2, grpBtn3, grpBtn4, pu_departmentChange]);
            $c.gus.cfEnableBtnOnly([btn_retrieve, btn_Clear, btn_Create, btn_1, btn_4, btn_9]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableObj(cnd_ed_mhno, true);
            $c.gus.cfEnableObjects([cnd_ed_mhno]); // 조회조건.
            scwin.f_EnableSearchObj(); // bulk search
            scwin.statusFlag = "I";
            break;

        case "RETRIEVE":  //조회모드
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_2, btn_3, btn_10
                , grpBtn1, grpBtn2, grpBtn3, grpBtn4]);
            $c.gus.cfEnableBtnOnly([btn_retrieve, btn_Clear, btn_Create, btn_Delete
                , btn_1, btn_4, btn_5, btn_6, btn_7, btn_9, pu_departmentChange]);
            // 그리드 수정 못하게 한다.  2008.01.16 국제물류 김미진씨 요청으로 B/L NO를 선택가능하게 하여 복사할 수 있게끔 처리 하기 위해 editable을 true로 처리함
            gr_houseblList.setReadOnly("grid", false);
            scwin.f_grdBlList(false);
            gr_ocCinvno.setReadOnly("grid", true);
            gr_selling.setReadOnly("grid", true);
            gr_buying.setReadOnly("grid", true);

            for (var i = 0; i < ds_selling.getTotalRow(); i++) {
                gr_selling.setCellReadOnly(i, "blNo", true);
                gr_selling.setCellReadOnly(i, "bilgClntNo", true);
                gr_selling.setCellReadOnly(i, "fareEngCd", true);
                gr_selling.setCellReadOnly(i, "crcCd", true);
                gr_selling.setCellReadOnly(i, "fareUnit", true);
                gr_selling.setCellReadOnly(i, "chgWt", true);
                gr_selling.setCellReadOnly(i, "sellUpr", true);
                gr_selling.setCellReadOnly(i, "sellAmtFcrc", true);
                gr_selling.setCellReadOnly(i, "exRate", true);
                gr_selling.setCellReadOnly(i, "sellAmt", true);
                gr_selling.setCellReadOnly(i, "vatAmt", true);
                gr_selling.setCellReadOnly(i, "rsltsStdDt", true);
                gr_selling.setCellReadOnly(i, "bulkBmk", true);
            }

            $c.gus.cfEnableObj(cnd_ed_mhno, true);
            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            $c.gus.cfEnableObjects([cnd_ed_mhno]); // 조회조건.
            scwin.f_EnableSearchObj(); // bulk search
            scwin.statusFlag = "";	 // flag null
            break;

        case "CREATE": //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_retrieve, btn_Create, btn_Update, btn_Delete, btn_1, btn_5, btn_6, btn_7, pu_departmentChange]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel
                , btn_2, btn_3, btn_10, btn_4, btn_9
                , grpBtn1, grpBtn2, grpBtn3, grpBtn4]);
            // 그리드 수정 가능
            gr_houseblList.setReadOnly("grid", false);
            scwin.f_grdBlList(true);
            gr_ocCinvno.setReadOnly("grid", false);
            gr_selling.setReadOnly("grid", false);
            gr_buying.setReadOnly("grid", false);
            $c.gus.cfEnableObj(cnd_ed_mhno, false);
            $c.gus.cfDisableObjects([cnd_ed_mhno]); // 조회조건.
            scwin.f_DisableSearchObj(); // bulk search
            scwin.statusFlag = "C";
            break;

        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_retrieve, btn_Update, btn_Delete, btn_Create, btn_1, btn_5, btn_6, btn_7]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel
                , btn_2, btn_3, btn_10, btn_4, btn_9
                , grpBtn1, grpBtn2, grpBtn3, grpBtn4, pu_departmentChange]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            // 그리드 수정 가능
            gr_houseblList.setReadOnly("grid", false);
            scwin.f_grdBlList(true);
            gr_ocCinvno.setReadOnly("grid", false);
            for (var i = 0; i < ds_houseblList.getTotalRow(); i++) {
                if (ds_houseblList.getRowStatus(i) == "C") {
                    gr_houseblList.setCellReadOnly(i, "hhblno", true);
                    gr_houseblList.setCellReadOnly(i, "odrNo", true);
                    gr_houseblList.setCellReadOnly(i, "hhbkgno", false);
                    gr_houseblList.setCellReadOnly(i, "hhbkgseq", false);
                    gr_houseblList.setCellReadOnly(i, "oblno", false);
                    gr_houseblList.setCellReadOnly(i, "hhactcust", true);
                    gr_houseblList.setCellReadOnly(i, "hhfaccd", false);
                    gr_houseblList.setCellReadOnly(i, "hhitem", false);
                    gr_houseblList.setCellReadOnly(i, "hhnwgt", false);
                    gr_houseblList.setCellReadOnly(i, "hhgwgt", false);
                    gr_houseblList.setCellReadOnly(i, "hhpkg", false);
                    gr_houseblList.setCellReadOnly(i, "hhmsr", false);
                    gr_houseblList.setCellReadOnly(i, "hhscd", false);
                    gr_houseblList.setCellReadOnly(i, "creadyDt", false);
                    gr_houseblList.setCellReadOnly(i, "lcDt", false);
                    gr_houseblList.setCellReadOnly(i, "srDt", false);
                    gr_houseblList.setCellReadOnly(i, "elDt", false);
                    gr_houseblList.setCellReadOnly(i, "bliDt", false);
                    gr_houseblList.setCellReadOnly(i, "bloDt", false);
                    gr_houseblList.setCellReadOnly(i, "hhrmk1", false);
                    gr_houseblList.setCellReadOnly(i, "hhcur", false);
                    gr_houseblList.setCellReadOnly(i, "hhexgb", false);
                    gr_houseblList.setCellReadOnly(i, "hhexrate", false);
                } else {
                    gr_houseblList.setCellReadOnly(i, "hhblno", true);
                    gr_houseblList.setCellReadOnly(i, "odrNo", true);
                    gr_houseblList.setCellReadOnly(i, "hhbkgno", true);
                    gr_houseblList.setCellReadOnly(i, "hhbkgseq", true);
                    gr_houseblList.setCellReadOnly(i, "oblno", false);
                    gr_houseblList.setCellReadOnly(i, "hhactcust", true);
                    gr_houseblList.setCellReadOnly(i, "hhfaccd", false);
                    gr_houseblList.setCellReadOnly(i, "hhitem", false);
                    gr_houseblList.setCellReadOnly(i, "hhnwgt", false);
                    gr_houseblList.setCellReadOnly(i, "hhgwgt", false);
                    gr_houseblList.setCellReadOnly(i, "hhpkg", false);
                    gr_houseblList.setCellReadOnly(i, "hhmsr", false);
                    gr_houseblList.setCellReadOnly(i, "hhscd", false);
                    gr_houseblList.setCellReadOnly(i, "creadyDt", false);
                    gr_houseblList.setCellReadOnly(i, "lcDt", false);
                    gr_houseblList.setCellReadOnly(i, "srDt", false);
                    gr_houseblList.setCellReadOnly(i, "elDt", false);
                    gr_houseblList.setCellReadOnly(i, "bliDt", false);
                    gr_houseblList.setCellReadOnly(i, "bloDt", false);
                    gr_houseblList.setCellReadOnly(i, "hhrmk1", false);
                    gr_houseblList.setCellReadOnly(i, "hhcur", false);
                    gr_houseblList.setCellReadOnly(i, "hhexgb", false);
                    gr_houseblList.setCellReadOnly(i, "hhexrate", false);
                }
            }


            gr_selling.setReadOnly("grid", true);
            gr_buying.setReadOnly("grid", true);
            for (var i = 0; i < ds_selling.getTotalRow(); i++) {
                if (ds_selling.getRowStatus(i) == "C") {
                    gr_selling.setCellReadOnly(i, "blNo", false);
                    gr_selling.setCellReadOnly(i, "bilgClntNo", false);
                    gr_selling.setCellReadOnly(i, "fareEngCd", false);
                    gr_selling.setCellReadOnly(i, "crcCd", false);
                    gr_selling.setCellReadOnly(i, "fareUnit", false);
                    gr_selling.setCellReadOnly(i, "chgWt", false);
                    gr_selling.setCellReadOnly(i, "sellUpr", false);
                    gr_selling.setCellReadOnly(i, "sellAmtFcrc", false);
                    gr_selling.setCellReadOnly(i, "exRate", false);
                    gr_selling.setCellReadOnly(i, "sellAmt", false);
                    gr_selling.setCellReadOnly(i, "vatAmt", false);
                    gr_selling.setCellReadOnly(i, "rsltsStdDt", false);
                    gr_selling.setCellReadOnly(i, "bulkBmk", false);
                } else {
                    gr_selling.setCellReadOnly(i, "sellAmtFcrc", ds_selling.getCellData(i, "sellAmtFcrc") == 0);
                    gr_selling.setCellReadOnly(i, "exRate", false);
                    gr_selling.setCellReadOnly(i, "sellAmt", false);
                    gr_selling.setCellReadOnly(i, "vatAmt", false);
                    gr_selling.setCellReadOnly(i, "rsltsStdDt", false);
                    gr_selling.setCellReadOnly(i, "bulkBmk", false);
                }
            }

            for (var i = 0; i < ds_buying.getTotalRow(); i++) {
                if (ds_buying.getRowStatus(i) == "C") {
                    gr_buying.setCellReadOnly(i, "pchsTyp", false);
                    gr_buying.setCellReadOnly(i, "pchsClntNo", false);
                    gr_buying.setCellReadOnly(i, "fareEngCd", false);
                    gr_buying.setCellReadOnly(i, "crcCd", false);
                    gr_buying.setCellReadOnly(i, "fareUnit", false);
                    gr_buying.setCellReadOnly(i, "chgWt", false);
                    gr_buying.setCellReadOnly(i, "pchsUpr", false);
                    gr_buying.setCellReadOnly(i, "pchsAmtFcrc", false);
                    gr_buying.setCellReadOnly(i, "exRate", false);
                    gr_buying.setCellReadOnly(i, "pchsAmt", false);
                    gr_buying.setCellReadOnly(i, "vat", false);
                    gr_buying.setCellReadOnly(i, "rsltsStdDt", false);
                } else {
                    gr_buying.setCellReadOnly(i, "pchsAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc") == 0);
                    gr_buying.setCellReadOnly(i, "rsltsStdDt", false);
                    gr_buying.setCellReadOnly(i, "vehclNo", false);
                }
            }

            $c.gus.cfEnableObj(cnd_ed_mhno, false);
            $c.gus.cfDisableObjects([cnd_ed_mhno]); // 조회조건.
            scwin.f_DisableSearchObj(); // bulk search
            scwin.statusFlag = "U";
            break;

        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create]);
            scwin.f_Set("RETRIEVE");

            break;
        //        	case "DELETE" :
        //            	$c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
        //            	$c.gus.cfEnableBtnOnly([btn_Create, btn_Update]);
        //            	scwin.f_Set("RETRIEVE");

        //            break;
    }

}

scwin.f_grdBlList = function (enable) {
    if (!enable) {
        gr_houseblList.setColumnDisableEdit("oblno", true);
        gr_houseblList.setColumnDisableEdit("hhfaccd", true);
        gr_houseblList.setColumnDisableEdit("hhitem", true);
        gr_houseblList.setColumnDisableEdit("hhnwgt", true);
        gr_houseblList.setColumnDisableEdit("hhgwgt", true);
        gr_houseblList.setColumnDisableEdit("hhpkg", true);
        gr_houseblList.setColumnDisableEdit("hhmsr", true);
        gr_houseblList.setColumnDisableEdit("hhscd", true);
        gr_houseblList.setColumnDisableEdit("creadyDt", true);
        gr_houseblList.setColumnDisableEdit("lcDt", true);
        gr_houseblList.setColumnDisableEdit("srDt", true);
        gr_houseblList.setColumnDisableEdit("elDt", true);
        gr_houseblList.setColumnDisableEdit("bliDt", true);
        gr_houseblList.setColumnDisableEdit("bloDt", true);
        gr_houseblList.setColumnDisableEdit("hhrmk1", true);
        gr_houseblList.setColumnDisableEdit("hhcur", true);
        gr_houseblList.setColumnDisableEdit("hhexgb", true);
        gr_houseblList.setColumnDisableEdit("hhcurdt", true);
        gr_houseblList.setColumnDisableEdit("hhexrate", true);
    } else {
        gr_houseblList.setColumnDisableEdit("oblno", false);
        gr_houseblList.setColumnDisableEdit("hhfaccd", false);
        gr_houseblList.setColumnDisableEdit("hhitem", false);
        gr_houseblList.setColumnDisableEdit("hhnwgt", false);
        gr_houseblList.setColumnDisableEdit("hhgwgt", false);
        gr_houseblList.setColumnDisableEdit("hhpkg", false);
        gr_houseblList.setColumnDisableEdit("hhmsr", false);
        gr_houseblList.setColumnDisableEdit("hhscd", false);
        gr_houseblList.setColumnDisableEdit("creadyDt", false);
        gr_houseblList.setColumnDisableEdit("lcDt", false);
        gr_houseblList.setColumnDisableEdit("srDt", false);
        gr_houseblList.setColumnDisableEdit("elDt", false);
        gr_houseblList.setColumnDisableEdit("bliDt", false);
        gr_houseblList.setColumnDisableEdit("bloDt", false);
        gr_houseblList.setColumnDisableEdit("hhrmk1", false);
        gr_houseblList.setColumnDisableEdit("hhcur", false);
        gr_houseblList.setColumnDisableEdit("hhexgb", false);
        gr_houseblList.setColumnDisableEdit("hhcurdt", false);
        gr_houseblList.setColumnDisableEdit("hhexrate", false);
    }
}

scwin.f_EnablePopUpObj = function () {
    // no-op: popup objects removed
    $c.gus.cfEnableObjects([udc_mhlinercd, udc_mhlinerattn, udc_mhvslcd, udc_mhitem, udc_hhactcust, udc_mhbuyer, udc_mhunitcd, udc_hhsales, udc_mhlodcd, udc_mhdisccd,btn_buyingSum]);

    txt_mhlinernm.setReadOnly(true);
    txt_hhactcustnm.setReadOnly(true);
    txt_hhsalesnm.setReadOnly(true);
}

scwin.f_DisablePopUpObj = function () {
    // no-op: popup objects removed
    $c.gus.cfDisableObjects([udc_mhlinercd, udc_mhlinerattn, udc_mhvslcd, udc_mhitem, udc_hhactcust, udc_mhbuyer, udc_mhunitcd, udc_hhsales, udc_mhlodcd, udc_mhdisccd,btn_buyingSum]);
}

scwin.f_EnableSearchObj = function () {
    $c.gus.cfEnableObjects([udc_cnd_ed_mhlinercd, udc_ed_mhetdFrom, udc_ed_mhvslcd, udc_ed_deptCd, cnd_txt_mhvyg]);
    $c.gus.cfEnableBtnOnly([btn_1]);
    gr_masterblList.setReadOnly("grid", true);
    gr_masterblList.setDisabled("grid", false);
}

scwin.f_DisableSearchObj = function () {
    $c.gus.cfDisableObjects([udc_cnd_ed_mhlinercd, udc_ed_mhetdFrom, udc_ed_mhvslcd, udc_ed_deptCd, cnd_txt_mhvyg]);
    $c.gus.cfDisableBtnOnly([btn_1]);
    gr_masterblList.setReadOnly("grid", true);
    gr_masterblList.setDisabled("grid", true);
}

