scwin.f_Retrieve = async function () {
    //scwin._resetHiddenDisplayFields();
    //	    	await $c.win.alert("조회후 작업 하십시요.");
    //	    	return;
    //	    }
    if (cnd_ed_mhno.getValue().trim() == "") {
        $c.gus.cfAlertMsg("Document No is mandatory.");  // @은(는) 필수 입력 항목입니다.
        return;
    }

    dma_retrieve.set("kcomcd", scwin.hd_kcomcd || "DBEX");
    dma_retrieve.set("mhno", cnd_ed_mhno.getValue());
    dma_retrieve.set("hhio", scwin.hd_hhio || "O");
    dma_retrieve.set("hhbltype", scwin.hd_hhbltype || "B");

    await $c.sbm.execute(sbm_retrieve);

    //cmd anable
    //		$c.gus.cfEnableObj(cnd_ed_mhno, true);

    //	    tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_mhno.focus() 잡아주기 위함.
    //    	cnd_ed_mhno.focus();
}

scwin.f_masterSearch = async function () {
    var ret = await $c.gus.cfValidate([cnd_ed_mhetdFrom, cnd_ed_mhetdTo]); //validExp 가 yes일때 check
    if (!ret) {
        return false;
    }

    if (cnd_ed_mhetdFrom.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["ETD From"]); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        cnd_ed_mhetdFrom.focus();
        return;
    }
    if (cnd_ed_mhetdTo.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["ETD To"]); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        cnd_ed_mhetdTo.focus();
        return;
    }

    dma_retrieveMaster.undo();
    dma_retrieveMaster.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieveMaster.set("mhio", scwin.hd_hhio);
    dma_retrieveMaster.set("mhlinercd", cnd_ed_mhlinercd.getValue());
    dma_retrieveMaster.set("mhlinernm", cnd_txt_mhlinernm.getValue());
    dma_retrieveMaster.set("mhvslcd", cnd_ed_mhvslcd.getValue());
    dma_retrieveMaster.set("mhvsl", cnd_txt_mhvsl.getValue());
    dma_retrieveMaster.set("mhvyg", cnd_txt_mhvyg.getValue());
    dma_retrieveMaster.set("mhetdFrom", cnd_ed_mhetdFrom.getValue());
    dma_retrieveMaster.set("mhetdTo", cnd_ed_mhetdTo.getValue());
    dma_retrieveMaster.set("deptCd", cnd_ed_deptCd.getValue());

    await $c.sbm.execute(sbm_retrieveMaster);
}


