scwin.f_Create = function () {
    scwin.f_FieldClear();
    scwin.f_dataSetClear();

    scwin.insertRow(ds_bulkblList);

    //cmd Disable
    //		$c.gus.cfEnableObj(cnd_ed_mhno, false);

    scwin.f_Set("CREATE");

    if (lc_hhexgb.getValue() == "") {
        lc_hhexgb.setValue(scwin.p_seaExgbEx);
    }
    if (lc_mexgb.getValue() == "") {
        lc_mexgb.setValue(scwin.p_seaExgbEx);
    }

    ed_hhcur.setValue("USD");
    ed_mhcur.setValue("USD");
    ed_mhpkg.setValue(0);
    ed_mhwgt.setValue(0);
    ed_mhmsr.setValue(0);
    ed_hhexrate.setValue(0);
    ed_hhuexrate.setValue(0);
    ed_mhexrate.setValue(0);
    ed_mhusdrate.setValue(0);
    tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_mhno.focus() 잡아주기 위함.
    ed_mhlinercd.focus();

}


