scwin.f_Update = function () {
    if (ed_mhetd.getValue() == "") { // 등록 화면에 필수인 ETD를 기준으로 잡았음.
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
        return;
    }

    //cmd Disable
    //		$c.gus.cfEnableObj(cnd_ed_mhno, false);
    $c.gus.cfDisableObjects([btn_Clear]);
    scwin.f_Set("UPDATE");
    // invoice check
    scwin.f_invoiceCheck(); // invoice Check
    if (scwin.invoiceCheck == "1") {
        $c.gus.cfDisableObjects([ed_mhbuyer, txt_mhbuyernm, img_PopUp6]);
    } else {
        $c.gus.cfEnableObjects([ed_mhbuyer, txt_mhbuyernm, img_PopUp6]);
    }
};

