scwin.f_Save = async function () {
    //scwin._syncHiddenDisplayToHouseInfo();
    var isChanged = (
        ds_bulkblList.getModifiedIndex().length > 0 ||
        ds_houseblList.getModifiedIndex().length > 0 ||
        ds_ocCinvno.getModifiedIndex().length > 0 ||
        ds_selling.getModifiedIndex().length > 0 ||
        ds_buying.getModifiedIndex().length > 0
    );

    if (!isChanged) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Bulk B/L"]); // @은(는) 변경된 사항이 없습니다.
        return;
    }

    if (await scwin.f_validate()) {
        if (ds_houseblList.getRowCount() == 0) {
            $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["House B/L Information"]); //  @이(가) 존재하지 않습니다.
            return;
        }
        if (await $c.win.confirm(E_MSG_CM_CRM_001)) { //저장하시겠습니까?
            if (scwin.statusFlag == "C") {
                // MHNO NO 를 생성및 가져온다.
                dma_retrieve.set("hhblno", "BE");
                dma_retrieve.set("hhetd", ed_mhetd.getValue());
                await $c.sbm.execute(sbm_createMhno);
                cnd_ed_mhno.setValue(ds_createMhno.getCellData(ds_createMhno.getRowPosition() ?? 0, "mhno"));

                // House B/L NO 를 생성및 가져온다.
                dma_retrieve.set("hhetd", ed_mhetd.getValue());
                await $c.sbm.execute(sbm_createHouseBlNo);
                scwin.hd_hhblno = ds_createBlNo.getCellData(ds_createBlNo.getRowPosition() ?? 0, "hhblno");

                // 저장
                // Bulk Header
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "mhno", cnd_ed_mhno.getValue());
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "mhio", scwin.hd_hhio);
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "inpid", scwin.userId);

                // house b/l sum
                var checked = 0;
                var v_wgt = 0;
                var v_pkg = 0;
                var v_msr = 0;
                for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
                    v_wgt += ds_houseblList.getCellData(i, "hhgwgt");
                    v_pkg += ds_houseblList.getCellData(i, "hhpkg");
                    v_msr += ds_houseblList.getCellData(i, "hhmsr");
                    checked++;
                }
                ed_mhpkg.setValue(v_pkg);
                ed_mhwgt.setValue(v_wgt);
                ed_mhmsr.setValue(v_msr);

                // House B/L Header
                var checked = 0;
                var j = 0;
                for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
                    if (ds_houseblList.getCellData(i, "hhblno") == "") {
                        var houseNo = "";
                        houseNo = String(Number(scwin.hd_hhblno.substr(7, 10)) + Number(j));
                        ds_houseblList.setCellData(i, "hhblno", scwin.hd_hhblno.substr(0, 6) + $c.gus.cfGetLeftPad(houseNo, "0", 4));
                        j++;
                    }
                    ds_houseblList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    ds_houseblList.setCellData(i, "mhno", cnd_ed_mhno.getValue());
                    ds_houseblList.setCellData(i, "hhbltype", scwin.hd_hhbltype);
                    ds_houseblList.setCellData(i, "autono", scwin.hd_autono);
                    ds_houseblList.setCellData(i, "hhio", scwin.hd_hhio);
                    ds_houseblList.setCellData(i, "hhetd", ed_mhetd.getValue());
                    ds_houseblList.setCellData(i, "hheta", ed_mheta.getValue());
                    ds_houseblList.setCellData(i, "inpid", scwin.userId);

                    // 2008. 05. 14 Vessel , Vessel Name  insert
                    ds_houseblList.setCellData(i, "hhvslcd", ed_mhvslcd.getValue());
                    ds_houseblList.setCellData(i, "hhvsl", txt_mhvsl.getValue());

                    // 2008.05. 27 Discharge 셋팅하기
                    ds_houseblList.setCellData(i, "hhdisccd", ed_mhdisccd.getValue());
                    ds_houseblList.setCellData(i, "hhdiscnm", txt_mhdiscnm.getValue());

                    checked++;
                }

                // Invoice
                var checked = 0;
                for (var i = 0; i < ds_ocCinvno.getRowCount(); i++) {
                    ds_ocCinvno.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    ds_ocCinvno.setCellData(i, "mhno", cnd_ed_mhno.getValue());
                    ds_ocCinvno.setCellData(i, "inpid", scwin.userId);
                    checked++;
                }
            } else if (scwin.statusFlag == "U") {
                // House B/L NO 를 생성및 가져온다.
                dma_retrieve.set("hhblno", "BE");
                dma_retrieve.set("hhetd", ed_mhetd.getValue());

                await $c.sbm.execute(sbm_createHouseBlNo);

                scwin.hd_hhblno = ds_createBlNo.getCellData(ds_createBlNo.getRowPosition() ?? 0, "hhblno");

                // 저장
                // Bulk Header
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "mhno", cnd_ed_mhno.getValue());
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "mhio", scwin.hd_hhio);
                ds_bulkblList.setCellData(ds_bulkblList.getRowPosition(), "inpid", scwin.userId);

                // house b/l sum
                var checked = 0;
                var v_wgt = 0;
                var v_pkg = 0;
                var v_msr = 0;
                for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
                    v_wgt += ds_houseblList.getCellData(i, "hhgwgt");
                    v_pkg += ds_houseblList.getCellData(i, "hhpkg");
                    v_msr += ds_houseblList.getCellData(i, "hhmsr");
                    checked++;
                }
                ed_mhpkg.setValue(v_pkg);
                ed_mhwgt.setValue(v_wgt);
                ed_mhmsr.setValue(v_msr);

                // House B/L Header
                var checked = 0;
                var j = 0;
                for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
                    if (ds_houseblList.getCellData(i, "hhblno") == "") {
                        var houseNo = "";
                        houseNo = String(Number(scwin.hd_hhblno.substr(7, 10)) + Number(j));
                        ds_houseblList.setCellData(i, "hhblno", scwin.hd_hhblno.substr(0, 6) + $c.gus.cfGetLeftPad(houseNo, "0", 4));
                        j++;
                    }
                    ds_houseblList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    ds_houseblList.setCellData(i, "mhno", cnd_ed_mhno.getValue());
                    ds_houseblList.setCellData(i, "hhbltype", scwin.hd_hhbltype);
                    ds_houseblList.setCellData(i, "autono", scwin.hd_autono);
                    ds_houseblList.setCellData(i, "hhio", scwin.hd_hhio);
                    ds_houseblList.setCellData(i, "hhetd", ed_mhetd.getValue());
                    ds_houseblList.setCellData(i, "hheta", ed_mheta.getValue());
                    ds_houseblList.setCellData(i, "creadyDt", ed_mhcrdt.getValue());
                    ds_houseblList.setCellData(i, "inpid", scwin.userId);
                    ds_houseblList.setCellData(i, "hhsales", ed_hhsales.getValue());  // 2008.03.14 추가 요청 Salesman수정추가
                    ds_houseblList.setCellData(i, "hhsalesnm", txt_hhsalesnm.getValue());

                    // 2008. 05. 14 Vessel , Vessel Name  update
                    ds_houseblList.setCellData(i, "hhvslcd", ed_mhvslcd.getValue());
                    ds_houseblList.setCellData(i, "hhvsl", txt_mhvsl.getValue());

                    // 2008.05. 27 Discharge 셋팅하기
                    ds_houseblList.setCellData(i, "hhdisccd", ed_mhdisccd.getValue());
                    ds_houseblList.setCellData(i, "hhdiscnm", txt_mhdiscnm.getValue());

                    checked++;
                }

                // Invoice
                var checked = 0;
                for (var i = 0; i < ds_ocCinvno.getRowCount(); i++) {
                    ds_ocCinvno.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    ds_ocCinvno.setCellData(i, "mhno", cnd_ed_mhno.getValue());
                    ds_ocCinvno.setCellData(i, "inpid", scwin.userId);
                    checked++;
                }
            }

            // 실행
            $c.sbm.execute(sbm_save);
        }
    }
};


