scwin.f_Cancel = function () {
    if (scwin.statusFlag == "C") {
        scwin.f_Set("INIT");
    } else {
        scwin.f_Set("RETRIEVE");
        ds_bulkblList.undoAll();
        scwin.f_cancelRow(1);
        scwin.f_cancelRow(2);
        scwin.f_cancelRow(3);
        scwin.f_cancelRow(4);
    }
    //$c.gus.cfEnableObjects([udc_cnd_ed_mhlinercd, udc_ed_mhvslcd, udc_ed_mhetdFrom, udc_ed_deptCd]); // 조회조건.
}

scwin.f_Delete = async function () {
    await scwin.f_invoiceCheck();

    if (scwin.invoiceCheck == "1") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
        return;
