}

//---------------------------------------------------------
scwin.f_addRow = function (disGubun) {
    // 2011.04.05 BKYOO 변경하지 않음
    switch (disGubun) {
        case 1:  	// HOUSE B/L
            scwin.insertRow(ds_houseblList);
            let houseIndex = ds_houseblList.getRowPosition() || 0;
            //ds_houseblList.setRowPosition(ds_houseblList.getTotalRow() - 1);
            ds_houseblList.setCellData(houseIndex, "hhactcust", ed_hhactcust.getValue());
            if (ed_hhactcust.getValue() != "") {
                scwin.f_PopUpGrid("Customer", houseIndex, "T");
            }
            ds_houseblList.setCellData(houseIndex, "hhsales", ed_hhsales.getValue());
            ds_houseblList.setCellData(houseIndex, "hhsalesnm", txt_hhsalesnm.getValue());
            ds_houseblList.setCellData(houseIndex, "hhincoterm", lc_hhincoterm.getValue());
            ds_houseblList.setCellData(houseIndex, "hhcur", ed_hhcur.getValue());
            ds_houseblList.setCellData(houseIndex, "hhexgb", lc_hhexgb.getValue());
            ds_houseblList.setCellData(houseIndex, "hhcurdt", ed_hhcurdt.getValue());
            ds_houseblList.setCellData(houseIndex, "hhexrate", ed_hhexrate.getValue());
            ds_houseblList.setCellData(houseIndex, "hhuexrate", ed_hhuexrate.getValue());

            ds_houseblList.setCellData(houseIndex, "hhliner", ed_mhlinercd.getValue());
            ds_houseblList.setCellData(houseIndex, "hhlinernm", txt_mhlinernm.getValue());
            ds_houseblList.setCellData(houseIndex, "hhlinerattn", ed_mhlinerattn.getValue());
            ds_houseblList.setCellData(houseIndex, "hhlinerattnnm", txt_mhlinerattnnm.getValue());
            ds_houseblList.setCellData(houseIndex, "hhvslcd", ed_mhvslcd.getValue());
            ds_houseblList.setCellData(houseIndex, "hhvsl", txt_mhvsl.getValue());
            ds_houseblList.setCellData(houseIndex, "hhvyg", txt_mhvyg.getValue());
            ds_houseblList.setCellData(houseIndex, "hhbuyer", ed_mhbuyer.getValue());
            ds_houseblList.setCellData(houseIndex, "hhbuyernm", txt_mhbuyernm.getValue());
            ds_houseblList.setCellData(houseIndex, "creadyDt", ed_mhcrdt.getValue());
            ds_houseblList.setCellData(houseIndex, "hhlodcd", ed_mhlodcd.getValue());
            ds_houseblList.setCellData(houseIndex, "hhlodnm", txt_mhlodnm.getValue());
            ds_houseblList.setCellData(houseIndex, "hhdisccd", ed_mhdisccd.getValue());
            ds_houseblList.setCellData(houseIndex, "hhdiscnm", txt_mhdiscnm.getValue());
            ds_houseblList.setCellData(houseIndex, "hhitem", ed_mhitem.getValue());
            ds_houseblList.setCellData(houseIndex, "hhmitem1", txt_mhitemNm.getValue());

            if (ds_houseblList.getRowCount() != 0) {
                ds_houseblList.setCellData(houseIndex, "hhbkgno", ds_houseblList.getCellData(houseIndex - 1, "hhbkgno"));
                ds_houseblList.setCellData(houseIndex, "hhbkgseq", ds_houseblList.getCellData(houseIndex - 1, "hhbkgseq"));
            };

            gr_houseblList.setCellReadOnly(houseIndex, "hhblno", true);
            gr_houseblList.setCellReadOnly(houseIndex, "odrNo", true);
            gr_houseblList.setCellReadOnly(houseIndex, "hhbkgno", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhbkgseq", false);
            gr_houseblList.setCellReadOnly(houseIndex, "oblno", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhactcust", true);
            gr_houseblList.setCellReadOnly(houseIndex, "hhfaccd", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhitem", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhnwgt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhgwgt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhpkg", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhmsr", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhscd", false);
            gr_houseblList.setCellReadOnly(houseIndex, "creadyDt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "lcDt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "srDt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "elDt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "bliDt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "bloDt", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhrmk1", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhcur", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhexgb", false);
            gr_houseblList.setCellReadOnly(houseIndex, "hhexrate", false);
            gr_houseblList.setFocusedCell(houseIndex, "hhblno"); // forcus
            break;

        case 2:  	// INVOICE
            // House B/L -> House B/L Null check (생성하기 위해 번호 따기 이전 작업-- 번호 생성후 다음 작업을 해야한다)
            var checked = 0;
            for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
                if (ds_houseblList.getCellData(i, "hhblno") == "") {
                    $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L Header"]);  // @은(는) 필수 입력 항목입니다.
                    return;
                }
                checked++;
            }

            if (ds_houseblList.getRowCount() == 0) {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L Header"]);  // @은(는) 필수 입력 항목입니다.
                return;
            } else {
                scwin.insertRow(ds_ocCinvno);
                ds_ocCinvno.setRowPosition(ds_ocCinvno.getTotalRow() - 1);
                ds_ocCinvno.setCellData(ds_ocCinvno.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
                ds_ocCinvno.setCellData(ds_ocCinvno.getRowPosition(), "cihblno", ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, "hhblno"));
                ds_ocCinvno.setCellData(ds_ocCinvno.getRowPosition(), "coblno", ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, "oblno"));
                ds_ocCinvno.setCellData(ds_ocCinvno.getRowPosition(), "mhno", cnd_ed_mhno.getValue());
                ds_ocCinvno.setCellData(ds_ocCinvno.getRowPosition(), "inpid", scwin.userId);
                gr_ocCinvno.setCellReadOnly(ds_ocCinvno.getRowPosition(), "ciinvno", false);
