scwin.f_deleteRow1 = function () {
    scwin.f_deleteRow(1);
}
scwin.f_deleteRow2 = function () {
    scwin.f_deleteRow(2);
}
scwin.f_deleteRow3 = function () {
    scwin.f_deleteRow(3);
}
scwin.f_deleteRow4 = function () {
    scwin.f_deleteRow(4);
}

scwin.f_deleteRow = function (disGubun) {
    switch (disGubun) {
        case 1:  	// HOUSE B/L
            if (ds_houseblList.getRowCount() == 1) {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["House B/L Information", "delete"]);  // @은(는) @할 수 없습니다.
            } else {
                scwin._deleteRow(ds_houseblList, ds_houseblList.getRowPosition() || 0);
            }
            break;

        case 2:    // INVOICE
            scwin._deleteRow(ds_ocCinvno, ds_ocCinvno.getRowPosition());
            break;

        case 3:  	//Selling
            if (ds_selling.getCellData(ds_selling.getRowPosition(), "certiNo") == "") {
                scwin._deleteRow(ds_selling, ds_selling.getRowPosition());
            } else {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                return;
            }
            break;

        case 4:  	// Buying
            if (ds_buying.getCellData(ds_buying.getRowPosition(), "pchsCertiNo") == "") {
                scwin._deleteRow(ds_buying, ds_buying.getRowPosition());
            } else {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                return;
            }
            break;

        default:
            break;
    }
};

//---------------------------------------------------------
// 행취소
//---------------------------------------------------------
scwin.f_cancelRow1 = function () {
    scwin.f_cancelRow(1);
}
scwin.f_cancelRow2 = function () {
    scwin.f_cancelRow(2);
}
scwin.f_cancelRow3 = function () {
    scwin.f_cancelRow(3);
}
scwin.f_cancelRow4 = function () {
    scwin.f_cancelRow(4);
}

scwin.f_cancelRow = function (disGubun) {
    switch (disGubun) {
        case 1:  	// HOUSE B/L
            ds_houseblList.undoAll();
            for (var i = 0; i < ds_houseblList.getTotalRow(); i++) {
                if (ds_houseblList.getRowStatus(i) == "C") ds_houseblList.removeRow(i);
            }
            break;

        case 2:  	 // INVOICE
            ds_ocCinvno.undoAll();
            for (var i = 0; i < ds_ocCinvno.getTotalRow(); i++) {
                if (ds_ocCinvno.getRowStatus(i) == "C") ds_ocCinvno.removeRow(i);
            }
            break;

        case 3:  	//Selling
            ds_selling.undoAll();
            for (var i = 0; i < ds_selling.getTotalRow(); i++) {
                if (ds_selling.getRowStatus(i) == "C") ds_selling.removeRow(i);
            }
            break;

        case 4:  	// Buying
            ds_buying.undoAll();
            for (var i = 0; i < ds_buying.getTotalRow(); i++) {
                if (ds_buying.getRowStatus(i) == "C") ds_buying.removeRow(i);
            }
            break;

        default:
            break;
    }
};

scwin.f_validate = async function () {
    var ret = await $c.gus.cfValidate([ed_mhcrdt, ed_mleta, ed_mhetd, ed_mheta, ed_mletd, ed_hhcurdt, ed_mhcurdt, gr_houseblList, gr_selling, gr_buying]); //validExp 가 yes일때 check
    if (!ret) {
        return false;
    }

    if (ed_hhcur.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]); //@는 필수입력항목입니다.
        ed_hhcur.focus();
        return false;
    }

    if (ed_mhcur.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]); //@는 필수입력항목입니다.
        ed_mhcur.focus();
        return false;
    }

    if (ed_mhetd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETD"]); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mhetd.focus();
        return false;
    }

    // 날짜 범위 확인
    if (ed_mheta.getValue() != "") {
        if (!await $c.gus.cfIsAfterDate(ed_mhetd.getValue(), ed_mheta.getValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("ETD", "ETA"));  //@은(는) 보다 작아야 합니다.
            tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_mhetd.focus();
            return false;
        }
    }

    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
    if ($c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_mhetd.getValue().toDate()) > 3) {
        await $c.win.alert("ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mhetd.focus();
        return false;
    }

    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
    if ($c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_mheta.getValue().toDate()) > 3) {
        await $c.win.alert("ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mheta.focus();
        return false;
    }

    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if ($c.gus.cfYearsBetween(ed_mhetd.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
        await $c.win.alert("ETD가 3년 이상의 과거 일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mhetd.focus();
        return false;
    }

    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if ($c.gus.cfYearsBetween(ed_mheta.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
        await $c.win.alert("ETA가 3년 이상의 과거 일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mheta.focus();
        return false;
    }

    //ETA-ETD(transit time)가 150일을 초과할 수 없다.  *150일(총 운항DATE 수) : ETA날짜에서 ETD날짜를 빼고 +1 한 날짜
    if ($c.date.diffDate(ed_mhetd.getValue(), ed_mheta.getValue()) > 149) {
        await $c.win.alert("ETA-ETD(transit time)가 150일을 초과할 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mhetd.focus();
        return false;
    }

    if (ed_mhbuyer.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department"]); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mhbuyer.focus();
        return false;
    }

    // item
    if (ed_mhitem.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_mhitem.focus();
        return false;
    }

    //item
    var checked = 0;
    for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
        if (ds_houseblList.getCellData(i, "hhitem") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]); //@는 필수입력항목입니다.
            gr_houseblList.focus();
            gr_houseblList.setFocusedCell(ds_houseblList.getRowPosition() || 0, "hhitem"); // forcus
            return false;
        }
        checked++;
    }

    //item name
    var checked = 0;
    for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
        if (ds_houseblList.getCellData(i, "hhmitem1") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item Name"]); //@는 필수입력항목입니다.
            gr_houseblList.focus();
            gr_houseblList.setFocusedCell(ds_houseblList.getRowPosition() || 0, "hhmitem1"); // forcus
            return false;
        }
        checked++;
    }

    // House B/L -> Booking No 필수 check
    var checked = 0;
    for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
        if (ds_houseblList.getCellData(i, "hhbkgno") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking No"]); //@는 필수입력항목입니다.
            gr_houseblList.focus();
            gr_houseblList.setFocusedCell(ds_houseblList.getRowPosition() || 0, "hhbkgno"); // forcus
            return false;
        }
        checked++;
    }

    // House B/L -> Booking No Seq 필수 check
    var checked = 0;
