        if (ds_houseblList.getCellData(i, "hhbkgseq") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Seq"]); //@는 필수입력항목입니다.
            gr_houseblList.focus();
            gr_houseblList.setFocusedCell(ds_houseblList.getRowPosition() || 0, "hhbkgseq"); // forcus
            return false;
        }
        checked++;
    }

    // Invoice -> House B/L No 필수 check
    var checked = 0;
    for (var i = 0; i < ds_ocCinvno.getRowCount(); i++) {
        if (ds_ocCinvno.getCellData(i, "cihblno") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L"]); //@는 필수입력항목입니다.
            gr_ocCinvno.focus();
            gr_ocCinvno.setFocusedCell(ds_ocCinvno.getRowPosition(), "cihblno"); // forcus
            return false;
        }
        checked++;
    }

    // Selling B/L No
    var checked = 0;
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "blNo") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]); //@는 필수입력항목입니다.
            gr_selling.focus();
            gr_selling.setFocusedCell(ds_selling.getRowPosition(), "blNo"); // forcus
            return false;
        }
        checked++;
    }

    // Selling Customer
    var checked = 0;
