//---------------------------------------------------------
// 공통팝업 열기
//---------------------------------------------------------
scwin.f_OpenCommonPopUp = function (gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    function normalizeRtn(rtnList) {
        if (!rtnList || rtnList == "N/A") {
            if (gubun1 == "DEPT2") cnd_ed_deptCd.setValue("");
            if (gubun1 == "VesselMaster") cnd_ed_mhvslcd.setValue("");
            return null;
        }
        if (rtnList.list && Array.isArray(rtnList.list)) rtnList = rtnList.list;
        if (Array.isArray(rtnList) && rtnList.length > 0 && Array.isArray(rtnList[0])) return rtnList[0];
        if (Array.isArray(rtnList)) return rtnList;
        var arr = [];
        if (rtnList.code != null) arr[0] = rtnList.code;
        if (rtnList.name != null) arr[1] = rtnList.name;
        return arr.length ? arr : null;
    }

    function getVal(comp) {
        if (!comp) return "";
        if (typeof comp.getValue === "function") return String(comp.getValue() || "");
        return "";
    }

    function setVal(comp, v) {
        if (!comp) return;
        if (typeof comp.setValue === "function") comp.setValue(v);
    }

    function openCommon(args) {
        var onReturn = function (rtnList) {
            var r = normalizeRtn(rtnList);
            if (!r) {
                if (typeof args.onEmpty === "function") args.onEmpty();
                return;
            }
            if (typeof args.onReturn === "function") args.onReturn(rtnList, r);
        };

        udc_ilcomCode.setSelectId(args.selectId);
        udc_ilcomCode.ilCommonPopUp(
            onReturn,
            getVal(args.codeComp),
            args.nameComp ? getVal(args.nameComp) : "",
            args.winCloseTF,
            args.colCnt,
            args.titles,
            args.widths,
            args.hideCols,
            args.whereOpt || "",
            args.winW || "500",
            args.winH || "500",
            args.posY || "",
            args.posX || "",
            args.dupTF || "",
            args.allTF || pAllSearchTF,
            args.winTitle || "",
            args.noDataTF || pNoDataCloseTF
        );
    }

    switch (gubun1) {
        case "Vessel":
            openCommon({
                selectId: "retrieveOrdVsslInfo",
                codeComp: ed_mhvslcd,
                nameComp: txt_mhvsl,
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "Vessel,Code,Name",
                onReturn: function (rtnList) { $c.gus.cfSetReturnValue(rtnList, ed_mhvslcd, txt_mhvsl); }
            });
            break;
        case "VesselMaster":
            openCommon({
                selectId: "retrieveOrdVsslInfo",
                codeComp: cnd_ed_mhvslcd,
                nameComp: null,
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "Vessel,Code,Name",
                onReturn: function (rtnList, r) {
                    setVal(cnd_ed_mhvslcd, r[0] || "");
                }
            });
            break;
        case "DEPT":
            openCommon({
                selectId: "retrieveOpDeptCdInfo",
                codeComp: ed_mhbuyer,
                nameComp: txt_mhbuyernm,
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "DEPT,Code,Name",
                onReturn: function (rtnList) { $c.gus.cfSetReturnValue(rtnList, ed_mhbuyer, txt_mhbuyernm); }
            });
            break;
        case "Unit":
            udc_mhunitcd.setSelectId('retrieveCommCdInfo');
            udc_mhunitcd.ilCommonPopUp(scwin.udc_mhunitcd
                , ed_mhunitcd.getValue()
                , txt_mhunit.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , 'IL002', null, null, null, null, null
                , pAllSearchTF
                , "Unit,Code,Name"
                , pNoDataCloseTF
            );
            break;
        case "Salesman":
            openCommon({
                selectId: "retrieveEmpInfo",
                codeComp: ed_hhsales,
                nameComp: txt_hhsalesnm,
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "Salesman,Code,Name",
                onReturn: function (rtnList) { $c.gus.cfSetReturnValue(rtnList, ed_hhsales, txt_hhsalesnm); }
            });
            break;
        case "Area":
            openCommon({
                selectId: "retrievePortInfo",
                codeComp: ed_mharea,
                nameComp: null,
                winCloseTF: pWinCloseTF,
                colCnt: "6",
                titles: "Code, Name,,,, UNCODE",
                widths: "80,160,,,,80",
                hideCols: "3,4,5,7,8,9,10",
                winTitle: "Area,Code,Name",
                onReturn: function (rtnList, r) {
                    setVal(ed_mharea, r[0] || "");
                    scwin.txt_mhareanm = String(r[1] || "");
                }
            });
            break;
        case "Loading":
            openCommon({
                selectId: "retrievePortInfo",
                codeComp: ed_mhlodcd,
                nameComp: txt_mhlodnm,
                winCloseTF: pWinCloseTF,
                colCnt: "6",
                titles: "Code, Name,,,, UNCODE",
                widths: "80,160,,,,80",
                hideCols: "3,4,5,7,8,9,10",
                winTitle: "Loading,Code,Name",
                onReturn: function (rtnList) { $c.gus.cfSetReturnValue(rtnList, ed_mhlodcd, txt_mhlodnm); }
            });
            break;
        case "Discharge":
            openCommon({
                selectId: "retrievePortInfo",
                codeComp: ed_mhdisccd,
                nameComp: txt_mhdiscnm,
                winCloseTF: pWinCloseTF,
                colCnt: "6",
                titles: "Code, Name,,,, UNCODE",
                widths: "80,160,,,,80",
                hideCols: "3,4,5,7,8,9,10",
                winTitle: "Discharge,Code,Name",
                onReturn: function (rtnList) { $c.gus.cfSetReturnValue(rtnList, ed_mhdisccd, txt_mhdiscnm); }
            });
            break;
        case "Item":
            openCommon({
                selectId: "retrieveCommGoodsInfo",
                codeComp: ed_mhitem,
                nameComp: txt_mhitemNm,
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "Item,Code,Name",
                onReturn: function (rtnList) { $c.gus.cfSetReturnValue(rtnList, ed_mhitem, txt_mhitemNm); }
            });
            break;
        case "DEPT2":
            openCommon({
                selectId: "retrieveOpDeptCdInfo",
                codeComp: udc_ed_deptCd,
                nameComp: cnd_txt_deptNm,
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "DEPT,Code,Name",
