//cmd anable        	
//-------------------------------------------------------------------------
// 화면이동
//-------------------------------------------------------------------------
scwin._getCommonParam = function () {
    var blno = "";
    if (ds_houseblList.getRowCount() > 0) {
        blno = ds_houseblList.getCellData(0, "hhblno") || "";
    }
    return {
        iogb: $c.str.trim(scwin.hd_hhio),
        kcomcd: $c.str.trim(scwin.hd_kcomcd),
        mhno: $c.str.trim(cnd_ed_mhno.getValue()),
        blno: $c.str.trim(blno)
    };
};

scwin._openMenu = function (title, path, menuId, param) {
    $c.win.openMenu(title, path, menuId, param || {});
};

scwin.f_openPgm = function (name) {
    var commonParam = scwin._getCommonParam();

    switch (name) {
        case "Booking":
            scwin._openMenu(
                "Bulk Booking",
                "/ui/il/seaout/sobk/se_102_01_01b.xml",
                "se_102_01_01b.xml"
            );
            break;
        case "Profit":
            scwin._openMenu(
                "Booking Sheet",
                "/ui/il/pfm/pfbs/pe_101_01_01b.xml",
                "pe_101_01_01b.xml",
                {
                    kcomcd: commonParam.kcomcd,
                    seaair: "S",
                    iogb: commonParam.iogb,
                    blno: commonParam.blno,
                    mblno: "",
                    mhno: commonParam.mhno
                }
            );
            break;
        case "paymentINV":
            scwin._openMenu(
                "Payment Invoice",
                "/ui/il/acc/acpay/ac_106_01_01b.xml",
                "ac_106_01_01b.xml",
                {
                    kcomcd: commonParam.kcomcd,
                    seaair: "S",
                    iogb: commonParam.iogb,
                    blno: "",
                    mblno: commonParam.mhno,
                    mhno: commonParam.mhno
                }
            );
            break;
        case "Invoice":
            scwin._openMenu(
                "Invoice",
                "/ui/il/acc/acinv/ac_101_01_01b.xml",
                "ac_101_01_01b.xml",
                {
                    kcomcd: commonParam.kcomcd,
                    seaair: "S",
                    iogb: commonParam.iogb,
                    blno: "",
                    mblno: commonParam.mhno,
                    mhno: commonParam.mhno
                }
            );
            break;
        case "BookingFind":
            scwin._openMenu(
                "Booking Search",
                "/ui/il/seaout/sobk/se_103_01_01b.xml",
                "se_103_01_01b.xml",
                { hhio: commonParam.iogb }
            );
            break;
    }
};


