            dma_retrieveTariff.set("loading", ed_mhlodcd.getValue()); //LOADING
            dma_retrieveTariff.set("discharge", ed_mhdisccd.getValue()); //DISCHARGE
            dma_retrieveTariff.set("item", ds_houseblList.getCellData(j, "hhitem")); //ITEM
            dma_retrieveTariff.set("container1", ""); //container1
            dma_retrieveTariff.set("container2", "");//container2
            dma_retrieveTariff.set("container3", "");//container3
            dma_retrieveTariff.set("container4", "");//container4
            dma_retrieveTariff.set("cbgubn", "B"); //CONTAINER OR BULK
            dma_retrieveTariff.set("incoterm", lc_hhincoterm.getValue()); //INCOTERM(bulk시 사용)
            dma_retrieveTariff.set("userid", scwin.userId); //user id
            dma_retrieveTariff.set("dangerous", ""); //dangerous
