                scwin.f_sellinghouseBlGridList(v_count, "");
                ds_selling.setCellData(v_count, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd"));	// fareEngCd
                scwin.f_PopUpGrid("SellingFcode", v_count, "T", "F"); //sellitemcd,faregrpcd,vatyn
                ds_selling.setCellData(v_count, "crcCd", ds_resultTariff.getCellData(i, "crcCd")); //cur
                ds_selling.setCellData(v_count, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit")); //unit
                scwin.f_packageRateSellingLoading(v_count, "");
                ds_selling.setCellData(v_count, "hhgwgt", ds_houseblList.getCellData(j, "hhgwgt"));	// g.weight
                ds_selling.setCellData(v_count, "sellUpr", ds_resultTariff.getCellData(i, "amount")); //rate
                scwin.f_sellingAmtFcrc(v_count, "");	//amount(외화)
                scwin.f_ExRateSellingGridLoading(); //ex-rate
                scwin.f_sellingAmt(v_count, "");	 //amount(원화)
                scwin.f_sellingVat(v_count, "");	//vat
                scwin.f_sellingUsdAmt(v_count, "");//auount($)
                checked++;
            }
            checked++;
        }
        gr_selling.focus();
        gr_selling.setFocusedCell(gr_selling.getFocusedRowIndex(), "bilgClntNo"); // forcus
        //scwin.f_MasterTariffAllLoading();

    }
};


