//cmd anable        	
//-------------------------------------------------------------------------
//Tariff All 가져오기 (Master)
//-------------------------------------------------------------------------
scwin.f_MasterTariffAllLoading = function () {
    if (ds_selling.getRowCount() != 0) {
        if (ds_buying.getRowCount() != 0) {
            $c.gus.cfAlertMsg(E_MSG_CM_WRN_011, ["Buying"]); // 이미 존재하는 @입니다.
            return;
        }

        // 지우고.
        ds_buying.setJSON([]);
        // 로우셋팅.
        var checked = 0;
        for (var i = 0; i < ds_selling.getRowCount(); i++) {
            var v_fcode = "";
            var v_cur = "";
            var v_unit = "";
            var v_weight = 0;
            v_fcode = ds_selling.getCellData(i, "fareEngCd");
            v_cur = ds_selling.getCellData(i, "crcCd");
            v_unit = ds_selling.getCellData(i, "fareUnit");
            v_weight = ds_selling.getCellData(i, "chgWt");
            v_rate = ds_selling.getCellData(i, "sellUpr");

            //이미 등록 되어 있는지 check
            var temp = 0;
            var checked = 0;
            var v_check = "";
            var v_checkno = 0;
            for (var j = 0; j < ds_buying.getRowCount(); j++) {
                if (ds_buying.getCellData(j, "fareEngCd") == v_fcode &&
                    ds_buying.getCellData(j, "crcCd") == v_cur &&
                    ds_buying.getCellData(j, "fareUnit") == v_unit) {
                    v_check = "T";
                    v_checkno = j;
                    break;
                } else {
                    v_check = "F";
                }
                checked++;
            }
            //buying 에 같은 값있으면 update 아니면 추가.
            if (v_check == "T") {
                ds_buying.setCellData(v_checkno, "chgWt", ds_buying.getCellData(v_checkno, "chgWt") + v_weight);
            } else {
                scwin.f_addRow(4); //kcomcd,blno,mhno,orderno,locptncls,mblhblcls,seaaircls,ppcccls,customer,customer name,실적일,inpid
                ds_buying.setCellData(ds_buying.getRowPosition(), "pchsTyp", "1"); //TYPE
                ds_buying.setCellData(ds_buying.getRowPosition(), "fareEngCd", v_fcode);  // fareEngCd
                scwin.f_PopUpGrid("BuyingFcode", ds_buying.getRowPosition(), "T", "F"); //selpchItemCd,fareGrpCd,vatyn
                ds_buying.setCellData(ds_buying.getRowPosition(), "crcCd", v_cur); //cur
                ds_buying.setCellData(ds_buying.getRowPosition(), "fareUnit", v_unit);  //unit
                ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", v_weight);  //weight
                ds_buying.setCellData(ds_buying.getRowPosition(), "pchsUpr", v_rate);	  //rate
            }

            checked++;
        }
        // 다른 값 반영.
        var checked = 0;
        for (var i = 0; i < ds_buying.getRowCount(); i++) {
            scwin.f_buyingAmtFcrc(i, "");	//amount(외화)
            scwin.f_ExRateBuyingGridLoading(); //ex-rate
            scwin.f_buyingAmt(i, "");	 //amount(원화)
            scwin.f_buyingVat(i, "");	//vat
            scwin.f_buyingUsdAmt(i, "");//auount($)

            checked++;
        }
    } else {
        $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
        return;
    }
};


//cmd anable        	
//-------------------------------------------------------------------------
//Customer,Ex-rate Change 가져오기 (Master)
//-------------------------------------------------------------------------
scwin.f_MasterExRateChange = async function () {
    if (ds_buying.getRowCount() == 0) {
        // $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Buying Information"]); //  @이(가) 존재하지 않습니다.
        $c.gus.cfAlertMsg("Buying Information does not exist."); //  @이(가) 존재하지 않습니다.
        return;
    }

    if (await $c.win.confirm("Do you wish to save?")) { //저장하시겠습니까?
        for (var i = 0; i < ds_buying.getRowCount(); i++) {
            ds_buying.setCellData(i, "exRate", ed_mhexrate.getValue()); //ex-rate
            scwin.f_buyingAmt(i, "");	 //amount(원화)
            scwin.f_buyingVat(i, "");	//vat
            scwin.f_buyingUsdAmt(i, "");//auount($)
        }
    }
    atmW = 0;
    vat = 0;
    amt = 0;
    amtTot = 0;
    for (var i = 0; i < ds_buying.getTotalRow(); i++) {
        atmW += Number(ds_buying.getCellData(i, "pchsAmt"));
        vat += Number(ds_buying.getCellData(i, "vat"));
        amt += Number(ds_buying.getCellData(i, "usdAmt"));
    }
    ed_BuyingSumAmount.setValue(amt);
    ed_BuyingSumAmountW.setValue(atmW);
    ed_BuyingSumVat.setValue(vat);
    ed_BuyingAmountSum.setValue(atmW + vat);
};


//cmd anable        	
//-------------------------------------------------------------------------
//tariff버튼 누르면 grid에 package ,rate계산 (Selling)
//-------------------------------------------------------------------------
scwin.f_packageRateSellingLoading = function (Row, Colid) {
    scwin.f_sellinghouseBlGridList(Row, Colid); // house 정보를 가져온다.
    var v_wgt = Number(ds_selling.getCellData(Row, "hhgwgt")) / 1000;
    var v_msr = Number(ds_selling.getCellData(Row, "hhmsr"));
    var v_wgtR = Math.ceil(v_wgt);
    var v_msrR = Math.ceil(v_msr);
    var wgt = 0;
    var msr = 0;
    if (ds_selling.getCellData(ds_selling.getRowPosition(), "fareEngCd") == "WFG") {
        wgt = v_wgtR;
        msr = v_msrR;
    } else {
        wgt = v_wgt;
        msr = v_msr;
    }
    if (ds_selling.getCellData(ds_selling.getRowPosition(), "fareUnit") == "WGT" || ds_selling.getCellData(ds_selling.getRowPosition(), "fareUnit") == "M/T") {
        if (ds_selling.getCellData(ds_selling.getRowPosition(), "fareEngCd") == "WFG") {
            ds_selling.setCellData(ds_selling.getRowPosition(), "chgWt", Math.ceil(Number(ds_selling.getCellData(Row, "hhgwgt"))));
        } else {
            ds_selling.setCellData(ds_selling.getRowPosition(), "chgWt", ds_selling.getCellData(Row, "hhgwgt"));
        }
    } else if (ds_selling.getCellData(ds_selling.getRowPosition(), "fareUnit") == "R/T") {
        if (v_wgt > v_msr) {
            ds_selling.setCellData(ds_selling.getRowPosition(), "chgWt", wgt);
        } else {
            ds_selling.setCellData(ds_selling.getRowPosition(), "chgWt", msr);
        }
    } else if (ds_selling.getCellData(ds_selling.getRowPosition(), "fareUnit") == "CBM") {
        ds_selling.setCellData(ds_selling.getRowPosition(), "chgWt", msr);
    } else if (ds_selling.getCellData(ds_selling.getRowPosition(), "fareUnit") == "CASE") {
        ds_selling.setCellData(ds_selling.getRowPosition(), "chgWt", "1");
    }
}


//cmd anable        	
//-------------------------------------------------------------------------
//tariff버튼 누르면 grid에 package ,rate계산 (buying)
//-------------------------------------------------------------------------
scwin.f_packageRateBuyingLoading = function (row, colid) {
