//-------------------------------------------------------------------------
scwin.f_sellingAmt = function (Row, Colid) {
    if (ds_selling.getCellData(Row, "crcCd") == "KRW") {
        ds_selling.setCellData(Row, "sellAmt", Math.round(ds_selling.getCellData(Row, "chgWt") * ds_selling.getCellData(Row, "sellUpr")));
