    param1 = strClntNo;
    await scwin._execDataId(ds_invoiceCheck, "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportHouseEBC&queryId=retriveInvoiceCheckCombo&param1=" + param1);
    if (ds_invoiceCheck.getCellData(ds_invoiceCheck.getRowPosition() || 0, "code") != "0") {
        scwin.invoiceCheck = "1";
    }
    // House Invoice Check
    var checked = 0;
    for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
        var strClntNo = "";
        strClntNo = ds_houseblList.getCellData(i, "odrNo");
        param1 = strClntNo;
        await scwin._execDataId(ds_invoiceCheck, "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportHouseEBC&queryId=retriveInvoiceCheckCombo&param1=" + param1);
        if (ds_invoiceCheck.getCellData(ds_invoiceCheck.getRowPosition() || 0, "code") != "0") {
            scwin.invoiceCheck = "1";
        }
        checked++;
    }
}


