//cmd anable        	
//-------------------------------------------------------------------------
//Selling sum
//-------------------------------------------------------------------------
scwin.f_SellingSum = function () {
    var checked = 0;

    var v_SellingSumAmount = 0;
    var v_SellingSumAmountW = 0;
    var v_SellingSumVat = 0;
    var v_SellingSumAmountUs = 0;
    var v_SellingAmountSum = 0;

    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getRowStatus(i) != "D") {
            v_SellingSumAmount = Number(v_SellingSumAmount) + Number(ds_selling.getCellData(i, "sellAmtFcrc"));
            v_SellingSumAmountW = Number(v_SellingSumAmountW) + Number(ds_selling.getCellData(i, "sellAmt"));
            v_SellingSumVat = Number(v_SellingSumVat) + Number(ds_selling.getCellData(i, "vatAmt"));
            v_SellingSumAmountUs = Number(v_SellingSumAmountUs) + Number(ds_selling.getCellData(i, "usdAmt"));
        }
        checked++;
    }
    ed_SellingSumAmount.setValue(v_SellingSumAmount);
    ed_SellingSumAmountW.setValue(v_SellingSumAmountW);
    ed_SellingSumVat.setValue(v_SellingSumVat);

    v_SellingAmountSum = Number(v_SellingSumAmountW) + Number(v_SellingSumVat);
    ed_SellingAmountSum.setValue(v_SellingAmountSum);
}


//cmd anable        	
//-------------------------------------------------------------------------
//Buying sum
//-------------------------------------------------------------------------
scwin.f_BuyingSum = function () {
    var checked = 0;

    var v_BuyingSumAmount = 0;
    var v_BuyingSumAmountW = 0;
    var v_BuyingSumVat = 0;
    var v_BuyingSumAmountUs = 0;
    var v_BuyingAmountSum = 0;

    for (var i = 0; i < ds_buying.getRowCount(); i++) {
        if (ds_buying.getRowStatus(i) != "2") {
            v_BuyingSumAmount = v_BuyingSumAmount + (Number(ds_buying.getCellData(i, "pchsAmtFcrc")) || 0);
            v_BuyingSumAmountW = v_BuyingSumAmountW + (Number(ds_buying.getCellData(i, "pchsAmt")) || 0);
            v_BuyingSumVat = v_BuyingSumVat + (Number(ds_buying.getCellData(i, "vat")) || 0);
            v_BuyingSumAmountUs = v_BuyingSumAmountUs + (Number(ds_buying.getCellData(i, "usdAmt")) || 0);
        }
        checked++;
    }
    ed_BuyingSumAmount.setValue(v_BuyingSumAmount);
    ed_BuyingSumAmountW.setValue(v_BuyingSumAmountW);
    ed_BuyingSumVat.setValue(v_BuyingSumVat);

    v_BuyingAmountSum = v_BuyingSumAmountW + v_BuyingSumVat;
    ed_BuyingAmountSum.setValue(v_BuyingAmountSum);
}


