    scwin.f_addRow(1);

}


//cmd anable        	
//-------------------------------------------------------------------------
// function	name : f_PopUpGrid
// function	desc : Grid popup
//-------------------------------------------------------------------------
scwin.f_PopUpGrid = function (disGubun, Row, pWinCloseTF, pAllSearchTF) {
    function normalizeRtn(rtnList) {
        if (!rtnList || rtnList == "N/A") return null;
        if (rtnList.list && Array.isArray(rtnList.list)) rtnList = rtnList.list;
        if (Array.isArray(rtnList) && rtnList.length > 0 && Array.isArray(rtnList[0])) return rtnList[0];
        if (Array.isArray(rtnList)) return rtnList;
        var arr = [];
        if (rtnList.code != null) arr[0] = rtnList.code;
        if (rtnList.name != null) arr[1] = rtnList.name;
        return arr.length ? arr : null;
    }

    function gv(ds, row, col) {
        return String(ds.getCellData(row, col) || "");
    }

    function openCommon(args) {
        var onReturn = function (rtnList) {
            var r = normalizeRtn(rtnList);
            if (!r) {
                if (typeof args.onEmpty === "function") args.onEmpty();
                return;
            }
            if (args.ds && args.row != null && args.codeCol) {
                args.ds.setCellData(args.row, args.codeCol, r[0] || "");
            }
            if (args.ds && args.row != null && args.nameCol) {
                args.ds.setCellData(args.row, args.nameCol, r[1] || "");
            }
            if (typeof args.afterFn === "function") args.afterFn(rtnList, r);
        };

        udc_ilcomCode.setSelectId(args.selectId);
        udc_ilcomCode.ilCommonPopUp(
            onReturn,
            args.codeValue || "",
            args.nameValue || "",
            args.winCloseTF,
            args.colCnt,
            args.titles,
            args.widths,
            args.hideCols,
            args.whereOpt || "",
            args.winW || "500",
            args.winH || "500",
            args.posY || "",
            args.posX || "",
            args.dupTF || "",
            args.allTF || pAllSearchTF,
            args.winTitle || "",
            args.noDataTF || "F"
        );
    }

    switch (disGubun) {
        case "Customer":
            openCommon({
                selectId: "retrieveEngClntInfo",
                ds: ds_houseblList,
                row: Row,
                codeCol: "hhactcust",
                nameCol: "hhactcustnm",
                codeValue: gv(ds_houseblList, Row, "hhactcust"),
                nameValue: gv(ds_houseblList, Row, "hhactcustnm"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                winTitle: "Customer search,Customer Code,Customer Name",
                noDataTF: "F"
            });
            break;
        case "Factory":
            openCommon({
                selectId: "retrieveEngClntInfo",
                ds: ds_houseblList,
                row: Row,
                codeCol: "hhfaccd",
                nameCol: "hhfacnm",
                codeValue: gv(ds_houseblList, Row, "hhfaccd"),
                nameValue: gv(ds_houseblList, Row, "hhfacnm"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Factory Code,Factory Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                winTitle: "Factory search,Factory Code,Factory Name",
                noDataTF: "F"
            });
            break;
        case "Item":
            openCommon({
                selectId: "retrieveCommGoodsInfo",
                ds: ds_houseblList,
                row: Row,
                codeCol: "hhitem",
                nameCol: "hhmitem1",
                codeValue: gv(ds_houseblList, Row, "hhitem"),
                nameValue: gv(ds_houseblList, Row, "hhmitem1"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "Item,Code,Name",
                noDataTF: "F"
            });
            break;
        case "Shipper":
            openCommon({
                selectId: "retrieveEngClntInfo",
                ds: ds_houseblList,
                row: Row,
                codeCol: "hhscd",
                nameCol: "hhs1",
                codeValue: gv(ds_houseblList, Row, "hhscd"),
                nameValue: gv(ds_houseblList, Row, "hhs1"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Shipper Code,Shipper Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                winTitle: "Shipper search,Shipper Code,Shipper Name",
                noDataTF: "F"
            });
            break;
        case "SellingCustomer":
            openCommon({
                selectId: "retrieveEngClntInfo",
                ds: ds_selling,
                row: Row,
                codeCol: "bilgClntNo",
                nameCol: "bilgClntNm",
                codeValue: gv(ds_selling, Row, "bilgClntNo"),
                nameValue: gv(ds_selling, Row, "bilgClntNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                winTitle: "Partner search,Partner Code,Partner Name",
                noDataTF: "F"
            });
            break;
        case "SellingFcode":
            openCommon({
                selectId: "retriveFreightCodeInfo",
                ds: ds_selling,
                row: Row,
                codeCol: "fareEngCd",
                nameCol: "fareEngNm",
                codeValue: gv(ds_selling, Row, "fareEngCd"),
                nameValue: gv(ds_selling, Row, "fareEngNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                whereOpt: "S,1",
                winTitle: "FCode,Code,Name",
                noDataTF: "F",
                afterFn: function (rtnList) {
                    ds_selling.setCellData(Row, "sellItemCd", rtnList[3]);
                    ds_selling.setCellData(Row, "fareGrpCd", rtnList[5]);
                    ds_selling.setCellData(Row, "vatYn", rtnList[7]);
                    if (rtnList[9] == "1") {
                        ds_selling.setCellData(Row, "crcCd", "KRW");
                    } else {
                        ds_selling.setCellData(Row, "crcCd", ed_hhcur.getValue());
                    }
                    if (ds_selling.getCellData(Row, "fareEngCd") == "OCF") {
                        ds_selling.setCellData(Row, "crcCd", "USD");
                    }
                }
            });
            break;
        case "BuyingCustomer":
            openCommon({
                selectId: "retrieveEngClntInfo",
                ds: ds_buying,
                row: Row,
                codeCol: "pchsClntNo",
                nameCol: "pchsClntNm",
                codeValue: gv(ds_buying, Row, "pchsClntNo"),
                nameValue: gv(ds_buying, Row, "pchsClntNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                winTitle: "Partner search,Partner Code,Partner Name",
                noDataTF: "F"
            });
            break;
        case "BuyingFcode":
            openCommon({
                selectId: "retriveFreightCodeInfo",
                ds: ds_buying,
                row: Row,
                codeCol: "fareEngCd",
                nameCol: "fareEngNm",
                codeValue: gv(ds_buying, Row, "fareEngCd"),
                nameValue: gv(ds_buying, Row, "fareEngNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                whereOpt: "S,2",
                winTitle: "FCode,Code,Name",
                noDataTF: "F",
                afterFn: function (rtnList) {
                    ds_buying.setCellData(Row, "selpchItemCd", rtnList[3]);
                    ds_buying.setCellData(Row, "fareGrpCd", rtnList[5]);
                    ds_buying.setCellData(Row, "vatYn", rtnList[7]);
                    if (rtnList[9] == "1") {
                        ds_buying.setCellData(Row, "crcCd", "KRW");
                    } else {
                        ds_buying.setCellData(Row, "crcCd", ed_mhcur.getValue());
                    }
                    if (ds_buying.getCellData(Row, "fareEngCd") == "OCF") {
                        ds_buying.setCellData(Row, "crcCd", "USD");
                    }
                }
            });
            break;
        case "BuyingDept":
            openCommon({
                selectId: "retrieveOpDeptCdInfo",
                ds: ds_buying,
                row: Row,
                codeCol: "sellDeptCd",
                nameCol: "sellDeptNm",
                codeValue: gv(ds_buying, Row, "sellDeptCd"),
                nameValue: gv(ds_buying, Row, "sellDeptNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                winTitle: "Department,Code,Name",
                noDataTF: "F"
            });
            break;
    }
}

