scwin.gr_houseblList_onviewchange = async function (info) {
    let Row = info.rowIndex;
    let Colid = info.colId;
    let totalRowCount = ds_houseblList.getRowCount();

    if (Row < 0 || Row > totalRowCount)
        return;

    switch (Colid) {

        case "hhbkgno":
            // BOOKING NO 로 SEQ SEARCH
            // if (ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhbkgno") == "") {
            //     scwin.f_bookingSearchPopup();
            // }
            // await scwin.f_BkSeqLoading();
            // ds_houseblList.setCellData(ds_houseblList.getRowPosition(), "hhbkgseq", ds_bkseq.getCellData(ds_bkseq.getRowPosition() ?? 0, "code"));
            // if (ds_bkseq.getRowCount() == 0) {
            //     ds_bkseq.insertRow();
            //     ds_bkseq.setRowPosition(0);
            //     ds_houseblList.setCellData(Row, "hhbkgseq", "");
            // }
            // scwin.f_HouseLoading(); //콤보변형시만 됨으로 최초 뿌려줌.
            // break;

        case "hhactcust":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_houseblList.getCellData(Row, Colid).trim() != "") {
                ds_houseblList.setCellData(Row, "hhactcustnm", "");
                scwin.f_PopUpGrid("Customer", Row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_houseblList.getCellData(Row, Colid).trim() == "") {
                ds_houseblList.setCellData(Row, "hhactcust", "");
                ds_houseblList.setCellData(Row, "hhactcustnm", "");
            }
            break;

        case "hhfaccd":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_houseblList.getCellData(Row, Colid).trim() != "") {
                ds_houseblList.setCellData(Row, "hhfacnm", "");
                scwin.f_PopUpGrid("Factory", Row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_houseblList.getCellData(Row, Colid).trim() == "") {
                ds_houseblList.setCellData(Row, "hhfaccd", "");
                ds_houseblList.setCellData(Row, "hhfacnm", "");
            }
            break;

        case "hhitem":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_houseblList.getCellData(Row, Colid).trim() != "") {
                ds_houseblList.setCellData(Row, "hhmitem1", "");
                scwin.f_PopUpGrid("Item", Row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_houseblList.getCellData(Row, Colid).trim() == "") {
                ds_houseblList.setCellData(Row, "hhitem", "");
                ds_houseblList.setCellData(Row, "hhmitem1", "");
            }
            break;

        case "hhscd":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_houseblList.getCellData(Row, Colid).trim() != "") {
                ds_houseblList.setCellData(Row, "hhs1", "");
                scwin.f_PopUpGrid("Shipper", Row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_houseblList.getCellData(Row, Colid).trim() == "") {
                ds_houseblList.setCellData(Row, "hhscd", "");
                ds_houseblList.setCellData(Row, "hhs1", "");
            }
            break;
        //환율 정보	
        case "hhcurdt":
            scwin.f_ExRateHouseGridLoading();
            break;

        default:
            break;
    }
};

scwin.gr_ocCinvno_oneditend = async function (rowIndex, columnIndex, value) {
    var Row = rowIndex;
    var Colid = gr_ocCinvno.getColumnID(columnIndex);
    var olddata = value;
    switch (Colid) {
        case "cihblno":
            if (ds_houseblList.getRowCount() != 0) {
                var param1 = "";
                var param2 = "";
                var param3 = "";
                param1 = scwin.hd_kcomcd;  //KCOMCD
                param2 = ds_ocCinvno.getCellData(Row, "cihblno"); // bl no
                param3 = cnd_ed_mhno.getValue(); //mhno
                ds_houseBlGridList.removeAll();
                await scwin._execDataId(ds_houseBlGridList, "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportBulkEBC&queryId=retriveHouseBlGridList&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3);
                if (ds_houseBlGridList.getRowCount() == 0) {
                    $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["House B/L"]); //  @이(가) 존재하지 않습니다.
                }
            }
            break;

        default:
            break;
    }
}

