scwin.gr_selling_onafteredit = function (rowIndex, columnIndex, value) {
    var Row = rowIndex;
    var Colid = gr_selling.getColumnID(columnIndex);
    switch (Colid) {
        case "bilgClntNo":
            if (value.trim() != "") {
                ds_selling.setCellData(Row, "bilgClntNm", "");
                scwin.f_PopUpGrid("SellingCustomer", Row, "T", "F", "F");
            } else {
                ds_selling.setCellData(Row, "bilgClntNo", "");
                ds_selling.setCellData(Row, "bilgClntNm", "");
            }
            break;

        case "fareEngCd":
            if (value.trim() != "") {
                ds_selling.setCellData(Row, "fareEngNm", "");
                scwin.f_PopUpGrid("SellingFcode", Row, "T", "F", "F");
            } else {
                ds_selling.setCellData(Row, "fareEngCd", "");
                ds_selling.setCellData(Row, "fareEngNm", "");
            }
            if (ds_selling.getCellData(Row, "fareEngCd") == "WFG") {
                scwin.f_packageRateSellingLoading(Row, "");
            }
            break;
        case "sellUpr":
            scwin.f_sellingAmtFcrc(Row, Colid);
            break;

        case "exRate":
            scwin.f_sellingAmt(Row, Colid);
            break;

        case "sellAmt":
            scwin.f_sellingVat(Row, Colid);
            break;

        case "vatAmt":
            scwin.f_sellingUsdAmt(Row, Colid);
            break;
        case "blNo":
            scwin.f_sellinghouseBlGridList(Row, Colid);
            break;
        case "fareUnit":
            scwin.f_packageRateSellingLoading(Row, Colid);
            scwin.f_sellingTariffRateLoading();
            break;

        default:
            break;
    }
};


