scwin.sbm_retrieve_submitdone = function (e) {
    if (ds_bulkblList.getRowCount() == 0) {
        $c.gus.cfAlertMsg("No data found./Could not find any relevant data."); //  해당되는 자료가 존재하지 않습니다
        scwin.f_Set("INIT");
        return;
    } else {
        ed_houseblList.setValue(ds_houseblList.getTotalRow());
        ed_ocCinvno.setValue(ds_ocCinvno.getTotalRow());
        ed_slipTax.setValue(ds_slipTax.getTotalRow());
        ed_ocProfitList.setValue(ds_ocProfitList.getTotalRow());
        ed_selling.setValue(ds_selling.getTotalRow());
        ed_buying.setValue(ds_buying.getTotalRow());
        ds_bulkblList.setRowPosition(0);
        ds_houseblList.setRowPosition(0);
        ds_ocCinvno.setRowPosition(0);
        ds_slipTax.setRowPosition(0);
        ds_ocProfitList.setRowPosition(0);
        ds_selling.setRowPosition(0);
        ds_buying.setRowPosition(0);
        scwin.f_invoiceCheck(); // invoice Check
        scwin.f_Set("RETRIEVE");
        scwin.f_SellingSum();
        scwin.f_BuyingSum();
        scwin.f_buyingUnitLoading();
        scwin.f_sellingUnitLoading();
        scwin.f_BkSeqLoading();
        scwin.f_sellingblNoLoading();
    }
}

scwin.sbm_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    scwin.f_Set("SAVE");
    $c.gus.cfAlertMsg(E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
    scwin.f_Retrieve();
}

scwin.sbm_delete_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await $c.gus.cfAlertMsg(E_MSG_CM_INF_004);
    scwin.f_FieldClear();
    scwin.f_dataSetClear();

    scwin.f_Set("INIT");
}

